#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform inorder traversal and store node values in a list
void inorderTraversal(TreeNode* root, int** list, int* size) {
    if (root) {
        inorderTraversal(root->left, list, size);
        (*list)[(*size)++] = root->val;
        inorderTraversal(root->right, list, size);
    }
}

// Function to check if there exist two elements in the BST that sum up to k
int findTarget(TreeNode* root, int k) {
    int* list = (int*) malloc(100000 * sizeof(int));
    int size = 0;
    inorderTraversal(root, &list, &size);
    int left = 0, right = size - 1;
    while (left < right) {
        int sum = list[left] + list[right];
        if (sum == k) return 1;
        else if (sum < k) left++;
        else right--;
    }
    return 0;
}

int main() {
    // Create the Binary Search Tree
    TreeNode* root = createTreeNode(7);
    root->left = createTreeNode(3);
    root->right = createTreeNode(10);
    root->left->left = createTreeNode(2);
    root->left->right = createTreeNode(6);
    root->right->left = createTreeNode(9);
    root->right->right = createTreeNode(11);
    root->left->left->left = createTreeNode(1);
    root->left->right->left = createTreeNode(5);
    root->left->right->right = createTreeNode(8);
    root->left->left->left->left = createTreeNode(4);
    int k = 12;
    printf("%d\n", findTarget(root, k));
    return 0;
}

